ruleContent.callBackJs:
let bu = String(book?book.tocUrl:"");
let mid = String(book?book.getVariable("mid"):"");
mid = mid || bu.match(/mid=(\d+)/)?.[1];
false;
if(event == "startRead"){
	if(/⚪️/.test(book.durChapterTitle)){
		java.toast("当前主播可能未开播，刷新目录再尝试进入");
		}
	}

    //定制
if (event == "clickCustomButton") {
     if(chapter&&/data:bilibili|series_id/.test(chapter.url)&&!/section/.test(bu)){
         let a = b64D(chapter.url).split("&")[0];
        let u = `https://api.bilibili.com/x/web-interface/archive/related?aid=${a}`
        java.open("explore", u, "推荐视频");
    }else if(/article\/view/.test(bu)) {
        java.openUrl("bilibili://article/cv" + bu.match(/id=(\d+)/)[1]);
    }else if(chapter && /data:liveurl/.test(chapter.url)){
        java.openUrl("bilibili://live/" + b64D(chapter.url).split("❌")[1]);
    }else if(/acc\/info/.test(bu)){
        java.openUrl("bilibili://space/" + bu.match(/mid=(\d+)/)[1]);
    }else if(/opus\/de/.test(bu)){
    	java.openUrl("bilibili://opus/detail/" + bu.match(/id=(\d+)/)[1]);
	}else if(/v1\/detail/.test(bu)){
        java.openUrl("bilibili://following/detail/" + (bu.match(/id=(\d+)/)?.[1] ?? book.durChapterTitle.match(/id(\d+)$/)[1]));
	}else if(chapter && /data:liveurl/.test(chapter.url)){
        java.openUrl("bilibili://live/" + b64(chapter.url));
    }else if(/article\/list/.test(bu)){
        java.openUrl("bilibili://article/readlist/" + bu.match(/id=(\d+)/)[1]);
    }else if(/reply\/reply/.test(bu)){
        java.toast("这里啥也没有")
    }else if(/season_id=/.test(bu)){
    	java.openUrl("bilibili://pgc/season/" + (bu.match(/_id=(\d+)/)?.[1]))
    	}else{
       java.openUrl("bilibili://video/av" + (bu.match(/[a_]id=(\d+)/)?.[1] ?? book.durChapterTitle.match(/id(\d+)$/)[1]));
    }

}

//分享
if (event == "clickShareBook") {
    let t = "";
    if (/article\/view/.test(bu)) {
        t = getShareUrl("article",bu.match(/opus\/(\d+)/)[1]);
        t = `我正在看 UP主：${book.author}的文章《${book.name}》\n文章链接：${t}`;
    }else if(/acc\/info/.test(bu)){
        t = getShareUrl("user",bu.match(/mid=(\d+)/)[1]);
        t = `我正在看 UP主：${book.name}\n访问主页：${t}`;
    }else if(/opus\/de/.test(bu)){
        t = getShareUrl("article",bu.match(/id=(\d+)/)[1]);
        t = `我正在看 UP主：${book.author}的动态《${book.name}》\n动态链接：${t}`;
	}else if(/v1\/detail/.test(bu)){
        t = getShareUrl("forward",(bu.match(/id=(\d+)/)?.[1] ?? book.durChapterTitle.match(/id(\d+)$/)[1]));
        t = `我正在看 UP主：${book.author}的动态《${book.name}》\n动态链接：${t}`;
	}else if(/article\/list/.test(bu)){
        t = getShareUrl("articlelist",bu.match(/id=(\d+)/)[1]);
        t = `我正在看 UP主：${book.author}的文集《${book.name}》\n文集链接：${t}`;
    }else if(/reply\/reply/.test(bu)){
        java.toast("这里啥也没有")
    }else if(/season_id/.test(bu)){
        t = getShareUrl("media_bangumi",bu.match(/id=(\d+)/)[1]);
        t = `我正在看剧集《${book.name}》\n剧集链接：${t}`;
    }else {
        t = getShareUrl("video",(bu.match(/aid=(\d+)/)?.[1] ?? book.durChapterTitle.match(/id(\d+)$/)[1]));
        t = `我正在看 UP主：${book.author}的视频《${book.name}》\n视频链接：${t}`;
    }

    java.copyText(t);
    java.toast("\n已复制，请去粘贴分享\n" + t);
    true
}

//书名
if (event == "clickBookName") {
    getMode();
    if(/series_id/.test(bu)) {
        java.open("explore", String(bu).replace(/pn=\d+/, 'pn={{page}\}'), "当前合集视频列表");
    }else if(/v1\/detail/.test(bu)){
        let u = getReply(bu.match(/id=(\d+)/)[1], 17, 3);
        java.open("explore", u, "热门评论");
    }else if(/article\/view/.test(bu)){
