function hasValidCustomSource() {
    const value = (source.getLoginInfoMap())['自定义源站'];
    return !(value == null || value == undefined || value == "" || String(value).trim() == "");
}

function showCustomSourceAlert() {
    const customSource = (source.getLoginInfoMap())['自定义源站'];
    java.toast(
        "\n⚠️ 自定义源站配置提醒 ⚠️\n" +
        "──────────────────\n" +
        "检测到已设置自定义源站: \n✨" +
        "【" + (customSource || "") + "】✨\n" +
        "──────────────────\n" +
        "请前往「书源登录」清除配置\n" +
        "才能使指定源站切换生效"
    );
}

function login(){
    const loginInfo = source.getLoginInfoMap();
    const email = loginInfo['邮箱'];
    const password = loginInfo['密码'];

    if (!email || !password) {
        java.toast("\n❌ 请先填写账号和密码并点击✓保存后登录");
        return;
    }

    java.toast("正在登录...");
    const host = getServerHost();
    const url = host + '/login.php';
    const body = "email=" + encodeURIComponent(email) + "&password=" + encodeURIComponent(password);

    try {
        const response = java.ajax(url + "," + JSON.stringify({
            method: "POST",
            body: body,
            timeout: 10000
        }));

        const result = JSON.parse(response);

        if (result.code == 200) {
            const user = result.data.user;
            const apiKey = user.api_key;

            source.putLoginHeader(apiKey);

            const nickname = user.nickname || "用户";
            const maskedEmail = email.includes('@') ? 
                email.substring(0, 3) + "****" + email.substring(email.indexOf('@')) : 
                email;

            java.toast(
                "\n───────────────\n" +
                "🌟 登录成功 🌟\n" +
                "───────────────\n" +
                "欢迎回来，" + nickname + "\n" +
                "邮箱：" + maskedEmail + "\n" +
                "───────────────"
            );
        } else {
            const errorCode = result.code || "未知";
            const errorMessage = result.message || "未知错误";

            java.toast(
                "\n───────────────\n" +
                "❌ 登录失败 ❌\n" +
                "───────────────\n" +
                "错误代码：" + errorCode + "\n" +
                "错误信息：" + errorMessage + "\n" +
                "───────────────"
            );
        }

    } catch (e) {
        java.toast(
            "\n───────────────\n" +
            "❌ 网络错误 ❌\n" +
            "───────────────\n" +
            "连接服务器失败\n" +
            "请检查网络连接\n" +
            "───────────────"
        );
    }
}

function user_logout() {
    let hadLogin = false;

    if (source.getLoginHeader() && String(source.getLoginHeader()).trim().length > 0) {
        hadLogin = true;
    }

    source.putLoginHeader("");

    if (!source.getLoginHeader() || String(source.getLoginHeader()).trim().length === 0) {
        java.toast(hadLogin ? "\n❗ 已成功退出登录" : "\nℹ️ 当前未登录状态");
    }
}

function updateConfig(key, value, message, gender) {
    if (key == "source" && hasValidCustomSource()) {
        showCustomSourceAlert();
        return;
    }

    try {
        var config = JSON.parse(source.getVariable());
        if (!config || !Array.isArray(config) || config.length === 0) {
            config = [{}];
        }
        config[0][key] = value;
        if (gender !== undefined) {
            config[0]["gender"] = gender;
        }
        source.setVariable(JSON.stringify(config));
        java.toast(message || "设置已更新");
    } catch(e) {
        var newConfig = {[key]: value};
        if (gender !== undefined) {
            newConfig["gender"] = gender;
        }
        source.setVariable(JSON.stringify([newConfig]));
        java.toast(message || "初始化设置");
    }
}

function get_user() {
    try {
        var encodedKey = getSecretKey();
        if (!encodedKey) {
            java.toast("❌ 未获取到密钥，请先登录");
            return;
        }

        var timestamp = Math.floor(Date.now() / 1000);
        var apiUrl = getServerHost() + '/query_key.php?key=' + encodedKey + '&t=' + timestamp;

        var response = java.ajax(apiUrl + "," + JSON.stringify({
            method: "GET",
            timeout: 10000
        }));

        var data = JSON.parse(response);

        if (data.data) {
            var userInfo = data.data;

            var statusDisplay = "";
            switch(userInfo.status) {
                case "正常":
                    statusDisplay = "✅ 正常";
                    break;
                case "会员":
                    statusDisplay = "👑会员";
                    break;
                case "封禁":
                    statusDisplay = "🚫 封禁";
                    break;
                default:
                    statusDisplay = userInfo.status;
            }

            var email = userInfo.email || "未绑定";
            var maskedEmail = "未绑定";
            if (email !== "未绑定" && email.includes("@")) {
                var parts = email.split("@");
                var username = parts[0];
                var domain = parts[1];
                if (username.length > 2) {
                    maskedEmail = username.substring(0, 2) + "****@" + domain;
                } else {
                    maskedEmail = username + "****@" + domain;
                }
            }

            var nickname = userInfo.nickname || "未设置";
            if (nickname === "未设置") {
                nickname = "👤 " + nickname;
            } else {
                nickname = "👤 " + nickname;
            }

            var displayContent = 
                "\n────────────\n" +
                "📊 用 户 信 息 📊\n" +
                "────────────\n" +
                nickname + "\n" +
                "────────────\n" +
                "📧 绑定邮箱\n" + maskedEmail + "\n" +
                "────────────\n" +
                "📊 累计阅读\n" + userInfo.total_usage + " 次\n" +
                "────────────\n" +
                "📈 今日阅读\n" + userInfo.today_usage + " 次\n" +
                "────────────\n" +
                "🔄 账户状态\n" + statusDisplay + "\n" +
                "────────────\n" +
                "📅 注册时间\n" + userInfo.created_at + "\n";

            if (userInfo.is_banned) {
                displayContent += "────────────\n" +
                                "🚫 封禁信息\n" + userInfo.banned_info + "\n";
            }

            if (userInfo.last_used !== "从未使用") {
                displayContent += "────────────\n" +
                                "⏰ 最后使用\n" + userInfo.last_used + "\n";
            }

            if (userInfo.is_member) {
                displayContent += "────────────\n" +
                                "👑会员状态\n 尊贵VIP会员\n";
            }

            displayContent += "────────────\n" +
                            "✨ 查询完成";

            java.longToast(displayContent);

        } else {
            var errorMsg = data.message || "未知错误";

            java.longToast(
                "❌ 查询失败：" + errorMsg
            );
        }

    } catch (e) {
        java.longToast(
            "❌ 网络连接异常，请稍后重试"
        );
    }
}

